//! Generate `.horus/Cargo.toml` from `horus.toml` dependencies.
//!
//! This module is the bridge between the unified horus manifest and the Cargo
//! build system. It reads `[dependencies]` from `horus.toml`, filters for
//! Rust-relevant deps (crates.io, path, git, registry), and produces a
//! valid `Cargo.toml` inside `.horus/`.
//!
//! The generated file is always gitignored and treated as a build artifact.

use anyhow::{Context, Result};
use colored::Colorize;
use std::collections::BTreeMap;
use std::fmt::Write as FmtWrite;
use std::fs;
use std::path::{Path, PathBuf};

use crate::manifest::{DepSource, DependencyValue, HorusManifest};

/// The `.horus` build directory name.
const HORUS_DIR: &str = ".horus";

/// Generate `.horus/Cargo.toml` from a `HorusManifest`.
///
/// - Filters crates.io, path, git, and registry deps from `[dependencies]`
/// - Adds horus_core/horus_library as path deps (found via `find_horus_source_dir`)
/// - Creates `[[bin]]` entries from source files
/// - Returns the path to the generated `Cargo.toml`
///
/// # Arguments
///
/// * `manifest` - The parsed horus.toml manifest
/// * `project_dir` - The project root directory (where horus.toml lives)
/// * `source_files` - List of .rs source files to create [[bin]] entries for
/// * `include_dev` - Whether to include dev-dependencies (for `horus test`)
pub fn generate(
    manifest: &HorusManifest,
    project_dir: &Path,
    source_files: &[PathBuf],
    include_dev: bool,
) -> Result<(PathBuf, String)> {
    let horus_dir = project_dir.join(HORUS_DIR);
    fs::create_dir_all(&horus_dir).context("Failed to create .horus directory")?;

    let project_name = &manifest.package.name;
    let version = &manifest.package.version;

    let mut cargo = String::with_capacity(2048);

    // ── Header ───────────────────────────────────────────────────────────
    writeln!(
        cargo,
        "# Generated by horus from horus.toml — do not edit manually"
    )
    .unwrap();
    writeln!(cargo, "[package]").unwrap();
    writeln!(cargo, "name = \"{}\"", sanitize_cargo_name(project_name)).unwrap();
    writeln!(cargo, "version = \"{}\"", version).unwrap();
    writeln!(cargo, "edition = \"2021\"").unwrap();
    writeln!(cargo).unwrap();

    // ── Workspace isolation ──────────────────────────────────────────────
    // Prevents inheriting a parent workspace
    writeln!(cargo, "[workspace]").unwrap();
    writeln!(cargo).unwrap();

    // ── Binary targets ───────────────────────────────────────────────────
    if source_files.is_empty() {
        // Default: look for main.rs in project root
        let main_rs = project_dir.join("main.rs");
        let src_main = project_dir.join("src/main.rs");
        if main_rs.exists() {
            write_bin_entry(
                &mut cargo,
                project_name,
                &relative_to_horus(&main_rs, &horus_dir),
            );
        } else if src_main.exists() {
            write_bin_entry(
                &mut cargo,
                project_name,
                &relative_to_horus(&src_main, &horus_dir),
            );
        }
    } else if source_files.len() == 1 {
        let rel = relative_to_horus(&source_files[0], &horus_dir);
        write_bin_entry(&mut cargo, project_name, &rel);
    } else {
        for file in source_files {
            let stem = file
                .file_stem()
                .map(|s| s.to_string_lossy().to_string())
                .unwrap_or_else(|| "main".to_string());
            let rel = relative_to_horus(file, &horus_dir);
            write_bin_entry(&mut cargo, &stem, &rel);
        }
    }

    // ── Auto-install missing registry deps ────────────────────────────────
    auto_install_registry_deps(&manifest.dependencies, project_dir, &horus_dir)?;
    if include_dev && !manifest.dev_dependencies.is_empty() {
        auto_install_registry_deps(&manifest.dev_dependencies, project_dir, &horus_dir)?;
    }

    // ── Dependencies ─────────────────────────────────────────────────────
    writeln!(cargo, "[dependencies]").unwrap();

    // Add horus core path deps
    if let Ok(horus_source) = crate::commands::run::find_horus_source_dir() {
        write_horus_path_deps(&mut cargo, &horus_source, manifest);
    }

    // Add user deps from horus.toml
    write_deps_section(&mut cargo, &manifest.dependencies, project_dir, &horus_dir)?;

    // Add driver dependencies from [drivers] config tables
    write_driver_deps(&mut cargo, &manifest.drivers);

    // ── Dev dependencies ─────────────────────────────────────────────────
    if include_dev && !manifest.dev_dependencies.is_empty() {
        writeln!(cargo).unwrap();
        writeln!(cargo, "[dev-dependencies]").unwrap();
        write_deps_section(
            &mut cargo,
            &manifest.dev_dependencies,
            project_dir,
            &horus_dir,
        )?;
    }

    // ── Write file ───────────────────────────────────────────────────────
    let cargo_toml_path = horus_dir.join("Cargo.toml");
    fs::write(&cargo_toml_path, &cargo)
        .with_context(|| format!("Failed to write {}", cargo_toml_path.display()))?;

    Ok((cargo_toml_path, cargo))
}

/// Write driver dependencies from `[drivers]` config tables.
///
/// For each `[drivers.NAME]` entry:
/// - `terra = "dynamixel"` → adds `terra-serial = { version = "0.2", features = ["dynamixel"] }`
/// - `package = "horus-driver-x"` → adds `horus-driver-x = "*"`
/// - `node = "MyDriver"` → no dependency (local code)
/// - `camera = "opencv"` / `gps = true` → no dependency (legacy, handled by feature flags)
fn write_driver_deps(
    cargo: &mut String,
    drivers: &std::collections::BTreeMap<String, crate::manifest::DriverValue>,
) {
    use crate::manifest::DriverValue;

    // Track crates already added to avoid duplicates (e.g., two drivers using terra-serial)
    let mut added_crates: std::collections::HashMap<String, Vec<String>> =
        std::collections::HashMap::new();

    for value in drivers.values() {
        match value {
            DriverValue::Config(cfg) => {
                // Terra drivers: no longer auto-resolved — user adds terra-horus
                // as a normal dependency in [dependencies]. Skip terra entries.
                if let Some(package) = &cfg.package {
                    if !added_crates.contains_key(package) {
                        added_crates.insert(package.clone(), Vec::new());
                    }
                } else if let Some(crate_name) = &cfg.crate_name {
                    // CratesIo driver — add the crate as a dependency
                    let _version = cfg.params.get("version")
                        .and_then(|v| v.as_str())
                        .unwrap_or("*")
                        .to_string();
                    added_crates.entry(crate_name.clone()).or_insert_with(|| {
                        // Store version as first "feature" entry (hacky but works with existing output logic)
                        // TODO: separate version tracking from features
                        Vec::new()
                    });
                }
                // pip/exec/sim3d/node → no Cargo dep needed
            }
            DriverValue::Backend(_) | DriverValue::Enabled(_) => {
                // Legacy — handled by feature flags in get_cargo_features_from_drivers()
            }
        }
    }

    if !added_crates.is_empty() {
        writeln!(cargo, "\n# Driver dependencies (from [drivers])").unwrap();
        for (crate_name, features) in &added_crates {
            if features.is_empty() {
                writeln!(cargo, "{} = \"*\"", crate_name).unwrap();
            } else {
                let features_str = features
                    .iter()
                    .map(|f| format!("\"{}\"", f))
                    .collect::<Vec<_>>()
                    .join(", ");
                writeln!(
                    cargo,
                    "{} = {{ version = \"*\", features = [{}] }}",
                    crate_name, features_str
                )
                .unwrap();
            }
        }
    }
}

/// Write a `[[bin]]` entry.
fn write_bin_entry(cargo: &mut String, name: &str, path: &str) {
    writeln!(cargo, "[[bin]]").unwrap();
    writeln!(cargo, "name = \"{}\"", sanitize_cargo_name(name)).unwrap();
    writeln!(cargo, "path = \"{}\"", path).unwrap();
    writeln!(cargo).unwrap();
}

/// Write horus core/library/macros path dependencies.
fn write_horus_path_deps(cargo: &mut String, horus_source: &Path, manifest: &HorusManifest) {
    // Detect hardware features from manifest
    let hw_features: Vec<&str> = manifest
        .drivers
        .keys()
        .filter_map(|k| match k.as_str() {
            "camera" => Some("camera"),
            "lidar" => Some("lidar"),
            "imu" => Some("imu"),
            "gps" => Some("gps"),
            _ => None,
        })
        .collect();

    for dep_name in &["horus", "horus_core", "horus_library", "horus_macros"] {
        let dep_path = horus_source.join(dep_name);
        if dep_path.exists() && dep_path.join("Cargo.toml").exists() {
            if (*dep_name == "horus" || *dep_name == "horus_library") && !hw_features.is_empty() {
                writeln!(
                    cargo,
                    "{} = {{ path = \"{}\", features = [{}] }}",
                    dep_name,
                    dep_path.display(),
                    hw_features
                        .iter()
                        .map(|f| format!("\"{}\"", f))
                        .collect::<Vec<_>>()
                        .join(", ")
                )
                .unwrap();
            } else {
                writeln!(
                    cargo,
                    "{} = {{ path = \"{}\" }}",
                    dep_name,
                    dep_path.display()
                )
                .unwrap();
            }
        }
    }
}

/// Write dependencies from a BTreeMap to Cargo.toml format.
///
/// Filters for Rust-compatible deps: crates.io, path, git.
/// Registry deps are resolved to path deps pointing to .horus/packages/.
/// PyPI and System deps are skipped (not relevant for Cargo).
///
/// For Simple deps that default to Registry, the smart source resolver is
/// consulted — if the package is a well-known crate, it's treated as crates.io.
fn write_deps_section(
    cargo: &mut String,
    deps: &std::collections::BTreeMap<String, DependencyValue>,
    project_dir: &Path,
    horus_dir: &Path,
) -> Result<()> {
    use crate::manifest::Language;
    use crate::source_resolver::PackageSourceResolver;
    let resolver = PackageSourceResolver::new(&[Language::Rust]);

    for (name, dep) in deps {
        let source = match dep.effective_source() {
            DepSource::Registry => {
                // Simple deps default to Registry — use smart resolver to check
                // if it's actually a well-known crates.io package.
                // Only upgrade with High confidence to avoid false positives.
                let resolved = resolver.resolve(name);
                if resolved.confidence == crate::source_resolver::Confidence::High {
                    resolved.source
                } else {
                    DepSource::Registry
                }
            }
            other => other,
        };
        match source {
            DepSource::CratesIo => {
                write_crates_io_dep(cargo, name, dep);
            }
            DepSource::Path => {
                if let DependencyValue::Detailed(d) = dep {
                    if let Some(ref p) = d.path {
                        // Resolve path relative to project dir, then make relative to .horus/
                        let abs_path = project_dir.join(p);
                        let rel = relative_to_horus(&abs_path, horus_dir);
                        writeln!(cargo, "{} = {{ path = \"{}\" }}", name, rel).unwrap();
                    }
                }
            }
            DepSource::Git => {
                if let DependencyValue::Detailed(d) = dep {
                    write_git_dep(cargo, name, d);
                }
            }
            DepSource::Registry => {
                // Registry packages are installed to .horus/packages/<name>/
                // If the package dir exists, add as path dep
                let pkg_dir = horus_dir.join("packages").join(name);
                if pkg_dir.exists() && pkg_dir.join("Cargo.toml").exists() {
                    writeln!(cargo, "{} = {{ path = \"packages/{}\" }}", name, name).unwrap();
                } else {
                    writeln!(
                        cargo,
                        "# {} = \"{}\" (registry, not yet installed)",
                        name,
                        dep.version().unwrap_or("*")
                    )
                    .unwrap();
                }
            }
            DepSource::PyPI | DepSource::System => {
                // Not Cargo deps — skip silently
            }
        }
    }
    Ok(())
}

/// Auto-install missing registry dependencies before Cargo.toml generation.
///
/// Scans the dependency map for `DepSource::Registry` entries, checks if each
/// is already present in `.horus/packages/<name>/`, and silently installs any
/// that are missing from the horus registry. This ensures `write_deps_section`
/// can emit real path deps instead of commented-out placeholders.
///
/// Failures are logged as warnings — the build continues and cargo will report
/// the missing crate with a clear error if auto-install didn't succeed.
fn auto_install_registry_deps(
    deps: &BTreeMap<String, DependencyValue>,
    project_dir: &Path,
    horus_dir: &Path,
) -> Result<()> {
    use crate::source_resolver::PackageSourceResolver;
    use crate::manifest::Language;

    let resolver = PackageSourceResolver::new(&[Language::Rust]);
    let mut missing: Vec<(String, Option<String>)> = Vec::new();

    for (name, dep) in deps {
        let source = match dep.effective_source() {
            DepSource::Registry => {
                let resolved = resolver.resolve(name);
                if resolved.confidence == crate::source_resolver::Confidence::High {
                    resolved.source
                } else {
                    DepSource::Registry
                }
            }
            other => other,
        };

        if source == DepSource::Registry {
            let pkg_dir = horus_dir.join("packages").join(name);
            if !pkg_dir.exists() || !pkg_dir.join("Cargo.toml").exists() {
                missing.push((name.clone(), dep.version().map(String::from)));
            }
        }
    }

    if missing.is_empty() {
        return Ok(());
    }

    eprintln!(
        "  {} Auto-installing {} registry package(s)...",
        crate::cli_output::ICON_INFO.cyan(),
        missing.len()
    );

    let client = crate::registry::RegistryClient::new();
    let target = crate::workspace::InstallTarget::Local(project_dir.to_path_buf());

    for (name, version) in &missing {
        eprintln!("    {} {}...", "v".cyan(), name);
        match client.install_from_registry(name, version.as_deref(), target.clone()) {
            Ok(v) => {
                eprintln!(
                    "    {} {} v{}",
                    crate::cli_output::ICON_SUCCESS.green(),
                    name,
                    v
                );
            }
            Err(e) => {
                // Warn but don't fail — cargo build will give a clear error
                eprintln!(
                    "    {} Failed to auto-install {}: {}",
                    crate::cli_output::ICON_WARN.yellow(),
                    name,
                    e
                );
            }
        }
    }

    Ok(())
}

/// Write a crates.io dependency line.
fn write_crates_io_dep(cargo: &mut String, name: &str, dep: &DependencyValue) {
    match dep {
        DependencyValue::Simple(v) => {
            writeln!(cargo, "{} = \"{}\"", name, v).unwrap();
        }
        DependencyValue::Detailed(d) => {
            let version = d.version.as_deref().unwrap_or("*");
            if d.features.is_empty() && !d.optional {
                writeln!(cargo, "{} = \"{}\"", name, version).unwrap();
            } else {
                let mut parts = vec![format!("version = \"{}\"", version)];
                if !d.features.is_empty() {
                    let feats = d
                        .features
                        .iter()
                        .map(|f| format!("\"{}\"", f))
                        .collect::<Vec<_>>()
                        .join(", ");
                    parts.push(format!("features = [{}]", feats));
                }
                if d.optional {
                    parts.push("optional = true".to_string());
                }
                writeln!(cargo, "{} = {{ {} }}", name, parts.join(", ")).unwrap();
            }
        }
    }
}

/// Write a git dependency line.
fn write_git_dep(cargo: &mut String, name: &str, d: &crate::manifest::DetailedDependency) {
    let git_url = d.git.as_deref().unwrap_or("");
    let mut parts = vec![format!("git = \"{}\"", git_url)];
    if let Some(ref branch) = d.branch {
        parts.push(format!("branch = \"{}\"", branch));
    }
    if let Some(ref tag) = d.tag {
        parts.push(format!("tag = \"{}\"", tag));
    }
    if let Some(ref rev) = d.rev {
        parts.push(format!("rev = \"{}\"", rev));
    }
    writeln!(cargo, "{} = {{ {} }}", name, parts.join(", ")).unwrap();
}

/// Compute a relative path from `.horus/` to a file.
///
/// e.g., `/home/user/project/main.rs` from `/home/user/project/.horus/`
/// → `../main.rs`
fn relative_to_horus(file: &Path, horus_dir: &Path) -> String {
    // Try to compute relative path
    if let Ok(rel) = pathdiff(file, horus_dir) {
        rel
    } else {
        // Fallback to absolute
        file.to_string_lossy().to_string()
    }
}

/// Simple relative path computation (from -> to).
fn pathdiff(target: &Path, base: &Path) -> Result<String, ()> {
    // Canonicalize if possible, otherwise use as-is
    let target = target
        .canonicalize()
        .unwrap_or_else(|_| target.to_path_buf());
    let base = base.canonicalize().unwrap_or_else(|_| base.to_path_buf());

    let mut target_parts: Vec<_> = target.components().collect();
    let mut base_parts: Vec<_> = base.components().collect();

    // Remove common prefix
    while !target_parts.is_empty() && !base_parts.is_empty() && target_parts[0] == base_parts[0] {
        target_parts.remove(0);
        base_parts.remove(0);
    }

    // Go up for remaining base parts, then down for target parts
    let mut result = String::new();
    for _ in &base_parts {
        if !result.is_empty() {
            result.push('/');
        }
        result.push_str("..");
    }
    for part in &target_parts {
        if !result.is_empty() {
            result.push('/');
        }
        result.push_str(&part.as_os_str().to_string_lossy());
    }

    if result.is_empty() {
        result.push('.');
    }

    Ok(result)
}

/// Sanitize a name for use as a Cargo package/bin name.
///
/// Replaces characters that are invalid in Cargo names with underscores.
pub fn sanitize_cargo_name(name: &str) -> String {
    name.chars()
        .map(|c| {
            if c.is_ascii_alphanumeric() || c == '_' || c == '-' {
                c
            } else {
                '_'
            }
        })
        .collect()
}

// ─── Workspace generation ────────────────────────────────────────────────────

use crate::manifest::{resolve_workspace_members, TargetType};

/// Smart dispatcher: routes to single-package or workspace generation.
///
/// If the manifest has `[workspace]`, generates a Cargo workspace.
/// Otherwise, falls through to the existing single-package `generate()`.
pub fn generate_for_manifest(
    manifest: &HorusManifest,
    project_dir: &Path,
    source_files: &[PathBuf],
    include_dev: bool,
) -> Result<(PathBuf, String)> {
    if let Some(ref ws) = manifest.workspace {
        let members = resolve_workspace_members(ws, project_dir)?;
        generate_workspace(manifest, project_dir, &members)
    } else {
        generate(manifest, project_dir, source_files, include_dev)
    }
}

/// Generate a Cargo workspace from a multi-member horus workspace.
///
/// Produces:
/// - `.horus/Cargo.toml` with `[workspace]` section
/// - `.horus/{member_name}/Cargo.toml` for each member
///
/// Returns the root path and its content for fingerprinting.
pub fn generate_workspace(
    root_manifest: &HorusManifest,
    project_dir: &Path,
    members: &[(PathBuf, HorusManifest)],
) -> Result<(PathBuf, String)> {
    let horus_dir = project_dir.join(HORUS_DIR);
    fs::create_dir_all(&horus_dir).context("Failed to create .horus directory")?;

    // ── Auto-install missing registry deps (workspace + all members) ─────
    if let Some(ref ws) = root_manifest.workspace {
        if !ws.dependencies.is_empty() {
            auto_install_registry_deps(&ws.dependencies, project_dir, &horus_dir)?;
        }
    }
    for (_, member_manifest) in members {
        if !member_manifest.dependencies.is_empty() {
            auto_install_registry_deps(&member_manifest.dependencies, project_dir, &horus_dir)?;
        }
    }

    let mut root_cargo = String::with_capacity(2048);

    // ── Header ────────────────────────────────────────────────────────────
    writeln!(root_cargo, "# Generated by horus from horus.toml — do not edit manually").unwrap();

    // ── Workspace section ─────────────────────────────────────────────────
    writeln!(root_cargo, "[workspace]").unwrap();
    writeln!(root_cargo, "resolver = \"2\"").unwrap();

    // Members list — use sanitized package names as directory names within .horus/
    let member_names: Vec<String> = members
        .iter()
        .map(|(_, m)| sanitize_cargo_name(&m.package.name))
        .collect();
    write!(root_cargo, "members = [").unwrap();
    for (i, name) in member_names.iter().enumerate() {
        if i > 0 {
            write!(root_cargo, ", ").unwrap();
        }
        write!(root_cargo, "\"{}\"", name).unwrap();
    }
    writeln!(root_cargo, "]").unwrap();
    writeln!(root_cargo).unwrap();

    // ── Workspace dependencies ────────────────────────────────────────────
    let ws = root_manifest.workspace.as_ref();
    let ws_deps = ws.map(|w| &w.dependencies);
    let has_ws_deps = ws_deps.is_some_and(|d| !d.is_empty());

    if has_ws_deps || true {
        // Always write [workspace.dependencies] to include horus core deps
        writeln!(root_cargo, "[workspace.dependencies]").unwrap();

        // Auto-inject horus core path deps
        if let Ok(horus_source) = crate::commands::run::find_horus_source_dir() {
            for dep_name in &["horus", "horus_core", "horus_library", "horus_macros"] {
                let dep_path = horus_source.join(dep_name);
                if dep_path.exists() && dep_path.join("Cargo.toml").exists() {
                    writeln!(
                        root_cargo,
                        "{} = {{ path = \"{}\" }}",
                        dep_name,
                        dep_path.display()
                    )
                    .unwrap();
                }
            }
        }

        // User workspace deps
        if let Some(deps) = ws_deps {
            write_deps_section(&mut root_cargo, deps, project_dir, &horus_dir)?;
        }
        writeln!(root_cargo).unwrap();
    }

    // ── If root also has a [package], include it as a member ──────────────
    if !root_manifest.package.name.is_empty() {
        // Root package goes into .horus/ directly (uses the root's source files)
        // For now, root packages in workspace mode use the single-package generate()
        // which already writes to .horus/Cargo.toml — skip for virtual workspaces.
    }

    // ── Generate per-member Cargo.toml ────────────────────────────────────
    for (rel_path, member_manifest) in members {
        let member_name = sanitize_cargo_name(&member_manifest.package.name);
        let member_horus_dir = horus_dir.join(&member_name);
        fs::create_dir_all(&member_horus_dir)
            .with_context(|| format!("Failed to create .horus/{}", member_name))?;

        let member_source_dir = project_dir.join(rel_path);
        let member_cargo = generate_member_cargo(
            &member_name,
            member_manifest,
            &member_source_dir,
            &member_horus_dir,
            root_manifest,
            members,
            &horus_dir,
        )?;

        let member_cargo_path = member_horus_dir.join("Cargo.toml");
        fs::write(&member_cargo_path, &member_cargo)
            .with_context(|| format!("Failed to write {}", member_cargo_path.display()))?;
    }

    // ── Write root Cargo.toml ─────────────────────────────────────────────
    let root_path = horus_dir.join("Cargo.toml");
    fs::write(&root_path, &root_cargo)
        .with_context(|| format!("Failed to write {}", root_path.display()))?;

    Ok((root_path, root_cargo))
}

/// Generate a member's Cargo.toml content.
fn generate_member_cargo(
    member_name: &str,
    member_manifest: &HorusManifest,
    member_source_dir: &Path,
    member_horus_dir: &Path,
    _root_manifest: &HorusManifest,
    all_members: &[(PathBuf, HorusManifest)],
    horus_dir: &Path,
) -> Result<String> {
    let mut cargo = String::with_capacity(1024);

    writeln!(cargo, "# Generated by horus — do not edit").unwrap();

    // ── [package] ─────────────────────────────────────────────────────────
    writeln!(cargo, "[package]").unwrap();
    writeln!(cargo, "name = \"{}\"", member_name).unwrap();
    writeln!(cargo, "version = \"{}\"", member_manifest.package.version).unwrap();
    let edition = member_manifest
        .package
        .rust_edition
        .as_deref()
        .unwrap_or("2021");
    writeln!(cargo, "edition = \"{}\"", edition).unwrap();
    writeln!(cargo).unwrap();

    // ── Target sections ───────────────────────────────────────────────────
    let target = &member_manifest.package.target_type;

    if matches!(target, TargetType::Lib | TargetType::Both) {
        let lib_path = member_source_dir.join("src/lib.rs");
        if lib_path.exists() {
            let rel = relative_to_horus(&lib_path, member_horus_dir);
            writeln!(cargo, "[lib]").unwrap();
            writeln!(cargo, "path = \"{}\"", rel).unwrap();
            writeln!(cargo).unwrap();
        }
    }

    if matches!(target, TargetType::Bin | TargetType::Both) {
        let main_path = member_source_dir.join("src/main.rs");
        let root_main = member_source_dir.join("main.rs");
        if main_path.exists() {
            let rel = relative_to_horus(&main_path, member_horus_dir);
            write_bin_entry(&mut cargo, &member_manifest.package.name, &rel);
        } else if root_main.exists() {
            let rel = relative_to_horus(&root_main, member_horus_dir);
            write_bin_entry(&mut cargo, &member_manifest.package.name, &rel);
        }
    }

    // ── [dependencies] ────────────────────────────────────────────────────
    writeln!(cargo, "[dependencies]").unwrap();

    // Horus core deps as workspace = true
    for dep_name in &["horus", "horus_core", "horus_library", "horus_macros"] {
        writeln!(cargo, "{}.workspace = true", dep_name).unwrap();
    }

    for (name, dep) in &member_manifest.dependencies {
        // workspace = true deps
        if let DependencyValue::Detailed(d) = dep {
            if d.workspace {
                if d.features.is_empty() {
                    writeln!(cargo, "{}.workspace = true", name).unwrap();
                } else {
                    writeln!(
                        cargo,
                        "{} = {{ workspace = true, features = [{}] }}",
                        name,
                        d.features
                            .iter()
                            .map(|f| format!("\"{}\"", f))
                            .collect::<Vec<_>>()
                            .join(", ")
                    )
                    .unwrap();
                }
                continue;
            }
        }

        // Inter-member path deps — rewrite to .horus/ sibling
        if let DependencyValue::Detailed(d) = dep {
            if let Some(ref original_path) = d.path {
                if let Some(rewritten) = rewrite_member_path_dep(
                    original_path,
                    member_source_dir,
                    all_members,
                    horus_dir,
                    member_horus_dir,
                ) {
                    writeln!(cargo, "{} = {{ path = \"{}\" }}", name, rewritten).unwrap();
                    continue;
                }
                // Non-member path dep — relativize from member_horus_dir
                let abs_path = member_source_dir.join(original_path);
                let rel = relative_to_horus(&abs_path, member_horus_dir);
                writeln!(cargo, "{} = {{ path = \"{}\" }}", name, rel).unwrap();
                continue;
            }
        }

        // Regular deps (crates.io, git, etc.) — write as-is
        write_single_dep(&mut cargo, name, dep);
    }

    writeln!(cargo).unwrap();
    Ok(cargo)
}

/// Write a single dependency in Cargo.toml format.
fn write_single_dep(cargo: &mut String, name: &str, dep: &DependencyValue) {
    match dep {
        DependencyValue::Simple(v) => {
            writeln!(cargo, "{} = \"{}\"", name, v).unwrap();
        }
        DependencyValue::Detailed(d) => {
            let version = d.version.as_deref().unwrap_or("*");
            if !d.features.is_empty() {
                let feats = d
                    .features
                    .iter()
                    .map(|f| format!("\"{}\"", f))
                    .collect::<Vec<_>>()
                    .join(", ");
                if d.optional {
                    writeln!(
                        cargo,
                        "{} = {{ version = \"{}\", features = [{}], optional = true }}",
                        name, version, feats
                    )
                    .unwrap();
                } else {
                    writeln!(
                        cargo,
                        "{} = {{ version = \"{}\", features = [{}] }}",
                        name, version, feats
                    )
                    .unwrap();
                }
            } else if let Some(ref git) = d.git {
                let mut parts = format!("{} = {{ git = \"{}\"", name, git);
                if let Some(ref branch) = d.branch {
                    parts.push_str(&format!(", branch = \"{}\"", branch));
                }
                if let Some(ref tag) = d.tag {
                    parts.push_str(&format!(", tag = \"{}\"", tag));
                }
                if let Some(ref rev) = d.rev {
                    parts.push_str(&format!(", rev = \"{}\"", rev));
                }
                parts.push_str(" }");
                writeln!(cargo, "{}", parts).unwrap();
            } else if d.optional {
                writeln!(
                    cargo,
                    "{} = {{ version = \"{}\", optional = true }}",
                    name, version
                )
                .unwrap();
            } else {
                writeln!(cargo, "{} = \"{}\"", name, version).unwrap();
            }
        }
    }
}

/// Detect inter-member path deps and rewrite to `.horus/` sibling directories.
fn rewrite_member_path_dep(
    original_path: &str,
    member_source_dir: &Path,
    all_members: &[(PathBuf, HorusManifest)],
    horus_dir: &Path,
    member_horus_dir: &Path,
) -> Option<String> {
    let target_dir = member_source_dir.join(original_path);
    let target_canonical = target_dir.canonicalize().ok()?;

    let project_dir = horus_dir.parent()?;

    for (rel_path, member_manifest) in all_members {
        let member_dir = project_dir.join(rel_path);
        if let Ok(member_canonical) = member_dir.canonicalize() {
            if member_canonical == target_canonical {
                let target_name = sanitize_cargo_name(&member_manifest.package.name);
                let target_horus = horus_dir.join(&target_name);
                return Some(relative_to_horus(&target_horus, member_horus_dir));
            }
        }
    }

    None
}

