    /// Helper to build a detailed dep with explicit source.
    fn detailed(
        source: DepSource,
        version: Option<&str>,
        features: &[&str],
        optional: bool,
    ) -> DependencyValue {
        DependencyValue::Detailed(DetailedDependency {
            version: version.map(|v| v.to_string()),
            source: Some(source),
            features: features.iter().map(|s| s.to_string()).collect(),
            optional,
            path: None,
            git: None,
            branch: None,
            tag: None,
            rev: None,
            apt: None,
            cmake_package: None,
            lang: None,
            workspace: false,
        })
    }

    fn git_dep(
        url: &str,
        branch: Option<&str>,
        tag: Option<&str>,
        rev: Option<&str>,
    ) -> DependencyValue {
        DependencyValue::Detailed(DetailedDependency {
            version: None,
            source: Some(DepSource::Git),
            features: vec![],
            optional: false,
            path: None,
            git: Some(url.to_string()),
            branch: branch.map(|s| s.to_string()),
            tag: tag.map(|s| s.to_string()),
            rev: rev.map(|s| s.to_string()),
            apt: None,
            cmake_package: None,
            lang: None,
            workspace: false,
        })
    }

    fn path_dep(p: &str) -> DependencyValue {
        DependencyValue::Detailed(DetailedDependency {
            version: None,
            source: Some(DepSource::Path),
            features: vec![],
            optional: false,
            path: Some(p.to_string()),
            git: None,
            branch: None,
            tag: None,
            rev: None,
            apt: None,
            cmake_package: None,
            lang: None,
            workspace: false,
        })
    }

    #[test]
    fn battle_mixed_deps_filters_correctly() {
        // Mix of crates.io, pypi, git, path, system — only Rust-relevant ones survive
        let dir = tempfile::tempdir().unwrap();
        fs::write(dir.path().join("main.rs"), "fn main() {}").unwrap();

        let mut deps = BTreeMap::new();
        deps.insert(
            "serde".into(),
            detailed(DepSource::CratesIo, Some("1.0"), &[], false),
        );
        deps.insert(
            "numpy".into(),
            detailed(DepSource::PyPI, Some(">=1.24"), &[], false),
        );
        deps.insert(
            "libz-sys".into(),
            detailed(DepSource::System, Some("1.0"), &[], false),
        );
        deps.insert(
            "my-fork".into(),
            git_dep("https://github.com/org/repo", Some("dev"), None, None),
        );

        // Create path dep directory so relative path resolves
        let lib_dir = dir.path().join("libs/mylib");
        fs::create_dir_all(&lib_dir).unwrap();
        deps.insert("mylib".into(), path_dep("libs/mylib"));

        let manifest = test_manifest(deps);
        let (result, _) = generate(&manifest, dir.path(), &[], false).unwrap();
        let content = fs::read_to_string(result).unwrap();

        // crates.io dep present
        assert!(content.contains("serde = \"1.0\""), "crates.io dep missing");
        // git dep present
        assert!(
            content
                .contains("my-fork = { git = \"https://github.com/org/repo\", branch = \"dev\" }"),
            "git dep missing"
        );
        // path dep present
        assert!(content.contains("mylib = { path ="), "path dep missing");
        // pypi dep filtered out
        assert!(!content.contains("numpy"), "pypi dep should be filtered");
        // system dep filtered out
        assert!(
            !content.contains("libz-sys"),
            "system dep should be filtered"
        );
    }

    #[test]
    fn battle_driver_features_propagation_camera_lidar() {
        // Drivers with camera + lidar should propagate features to horus/horus_library path deps.
        // We can't test the actual write_horus_path_deps without the horus source dir existing,
        // but we can test the hw_features extraction logic directly.
        let mut manifest = test_manifest(BTreeMap::new());
        manifest
            .drivers
            .insert("camera".into(), DriverValue::Backend("opencv".into()));
        manifest
            .drivers
            .insert("lidar".into(), DriverValue::Backend("rplidar-a2".into()));
        manifest.drivers.insert(
            "custom_sensor".into(),
            DriverValue::Backend("custom".into()),
        );

        // Extract features using the same logic as write_horus_path_deps
        let hw_features: Vec<&str> = manifest
            .drivers
            .keys()
            .filter_map(|k| match k.as_str() {
                "camera" => Some("camera"),
                "lidar" => Some("lidar"),
                "imu" => Some("imu"),
                "gps" => Some("gps"),
                _ => None,
            })
            .collect();

        assert!(hw_features.contains(&"camera"), "camera feature missing");
        assert!(hw_features.contains(&"lidar"), "lidar feature missing");
        assert_eq!(
            hw_features.len(),
            2,
            "custom_sensor should not produce a feature"
        );
    }

