    // ── Workspace generation tests ────────────────────────────────────────

    /// Helper: build a minimal HorusManifest without Default derive.
    fn empty_manifest() -> HorusManifest {
        HorusManifest {
            package: PackageInfo::default(),
            workspace: None,
            robot: None,
            dependencies: BTreeMap::new(),
            dev_dependencies: BTreeMap::new(),
            sim_dependencies: BTreeMap::new(),
            hardware: BTreeMap::new(),
            drivers: BTreeMap::new(),
            sim_drivers: BTreeMap::new(),
            scripts: BTreeMap::new(),
            ignore: IgnoreConfig::default(),
            enable: vec![],
            cpp: None,
            hooks: Default::default(),
            network: None,
        }
    }

    /// Helper: create a workspace root manifest + two member manifests for testing.
    ///
    /// Returns (root_manifest, members_vec, tempdir) where tempdir owns the
    /// filesystem lifetime. Caller must keep it alive.
    fn create_workspace_project() -> (
        HorusManifest,
        Vec<(PathBuf, HorusManifest)>,
        tempfile::TempDir,
    ) {
        let dir = tempfile::tempdir().unwrap();

        // Create directory structure:
        //   crates/messages/src/lib.rs
        //   crates/controller/src/main.rs
        let messages_dir = dir.path().join("crates/messages");
        let controller_dir = dir.path().join("crates/controller");
        fs::create_dir_all(messages_dir.join("src")).unwrap();
        fs::create_dir_all(controller_dir.join("src")).unwrap();
        fs::write(messages_dir.join("src/lib.rs"), "pub fn hello() {}").unwrap();
        fs::write(controller_dir.join("src/main.rs"), "fn main() {}").unwrap();

        // Root manifest — virtual workspace (empty package name)
        let root = HorusManifest {
            package: PackageInfo::default(), // name = "" → virtual workspace
            workspace: Some(WorkspaceConfig {
                members: vec!["crates/*".to_string()],
                exclude: vec![],
                dependencies: BTreeMap::from([(
                    "serde".to_string(),
                    DependencyValue::Simple("1.0".to_string()),
                )]),
            }),
            ..empty_manifest()
        };

        // Member: messages (lib)
        let messages = HorusManifest {
            package: PackageInfo {
                name: "my-messages".to_string(),
                version: "0.1.0".to_string(),
                target_type: TargetType::Lib,
                ..PackageInfo::default()
            },
            dependencies: BTreeMap::from([(
                "serde".to_string(),
                DependencyValue::Detailed(DetailedDependency {
                    workspace: true,
                    ..DetailedDependency::default()
                }),
            )]),
            ..empty_manifest()
        };

        // Member: controller (bin)
        let controller = HorusManifest {
            package: PackageInfo {
                name: "my-controller".to_string(),
                version: "0.2.0".to_string(),
                target_type: TargetType::Bin,
                ..PackageInfo::default()
            },
            dependencies: BTreeMap::new(),
            ..empty_manifest()
        };

        let members = vec![
            (PathBuf::from("crates/messages"), messages),
            (PathBuf::from("crates/controller"), controller),
        ];

        (root, members, dir)
    }

    // ── 1. Basic workspace generation ─────────────────────────────────────

    #[test]
    fn workspace_generate_root_cargo_toml() {
        let (root, members, dir) = create_workspace_project();
        let (path, content) = generate_workspace(&root, dir.path(), &members).unwrap();

        assert!(path.ends_with(".horus/Cargo.toml"), "wrong root path: {:?}", path);
        assert!(content.contains("[workspace]"), "missing [workspace]: {}", content);
        assert!(
            content.contains("resolver = \"2\""),
            "missing resolver = \"2\": {}",
            content
        );
        assert!(
            content.contains("\"my-messages\""),
            "missing my-messages member: {}",
            content
        );
        assert!(
            content.contains("\"my-controller\""),
            "missing my-controller member: {}",
            content
        );
        assert!(
            content.contains("[workspace.dependencies]"),
            "missing [workspace.dependencies]: {}",
            content
        );
        assert!(
            content.contains("serde = \"1.0\""),
            "missing serde workspace dep: {}",
            content
        );
    }

    #[test]
    fn workspace_generate_member_lib_cargo_toml() {
        let (root, members, dir) = create_workspace_project();
        generate_workspace(&root, dir.path(), &members).unwrap();

        let member_cargo_path = dir.path().join(".horus/my-messages/Cargo.toml");
        assert!(member_cargo_path.exists(), "member Cargo.toml not created");
        let content = fs::read_to_string(&member_cargo_path).unwrap();

        // [package] section
        assert!(
            content.contains("name = \"my-messages\""),
            "missing package name: {}",
            content
        );
        assert!(
            content.contains("version = \"0.1.0\""),
            "missing version: {}",
            content
        );

        // [lib] section with path back to source
        assert!(content.contains("[lib]"), "missing [lib] section: {}", content);
        assert!(
            content.contains("src/lib.rs"),
            "lib path should reference src/lib.rs: {}",
            content
        );

        // No [[bin]] section for a lib target
        assert!(
            !content.contains("[[bin]]"),
            "lib member should not have [[bin]]: {}",
            content
        );

        // workspace = true dep
        assert!(
            content.contains("serde.workspace = true"),
            "missing serde.workspace = true: {}",
            content
        );
    }

