    #[test]
    fn workspace_generate_inter_member_path_dep() {
        let dir = tempfile::tempdir().unwrap();

        // Create member directories
        fs::create_dir_all(dir.path().join("crates/messages/src")).unwrap();
        fs::create_dir_all(dir.path().join("crates/controller/src")).unwrap();
        fs::write(
            dir.path().join("crates/messages/src/lib.rs"),
            "pub fn msg() {}",
        )
        .unwrap();
        fs::write(
            dir.path().join("crates/controller/src/main.rs"),
            "fn main() {}",
        )
        .unwrap();

        let root = HorusManifest {
            workspace: Some(WorkspaceConfig {
                members: vec!["crates/*".to_string()],
                exclude: vec![],
                dependencies: BTreeMap::new(),
            }),
            ..empty_manifest()
        };

        let messages = HorusManifest {
            package: PackageInfo {
                name: "my-messages".to_string(),
                version: "0.1.0".to_string(),
                target_type: TargetType::Lib,
                ..PackageInfo::default()
            },
            ..empty_manifest()
        };

        // controller depends on messages via relative path
        let controller = HorusManifest {
            package: PackageInfo {
                name: "my-controller".to_string(),
                version: "0.2.0".to_string(),
                target_type: TargetType::Bin,
                ..PackageInfo::default()
            },
            dependencies: BTreeMap::from([(
                "my-messages".to_string(),
                DependencyValue::Detailed(DetailedDependency {
                    source: Some(DepSource::Path),
                    path: Some("../messages".to_string()),
                    ..DetailedDependency::default()
                }),
            )]),
            ..empty_manifest()
        };

        let members = vec![
            (PathBuf::from("crates/messages"), messages),
            (PathBuf::from("crates/controller"), controller),
        ];
        generate_workspace(&root, dir.path(), &members).unwrap();

        let content = fs::read_to_string(
            dir.path().join(".horus/my-controller/Cargo.toml"),
        )
        .unwrap();

        // The path dep should be rewritten to point to the sibling .horus/ dir
        assert!(
            content.contains("my-messages = { path ="),
            "inter-member path dep missing: {}",
            content
        );
        // Should point to ../my-messages (sibling within .horus/)
        assert!(
            content.contains("../my-messages"),
            "path dep should be rewritten to ../my-messages: {}",
            content
        );
    }

